import {
  ChangeDetectionStrategy,
  Component,
  computed,
  forwardRef,
  input,
  model,
  output,
  signal,
} from '@angular/core';
import { DRAWER_CONTEXT, type DrawerContext } from './drawer.context';

let _drawerIdCounter = 0;

@Component({
  selector: 'n-drawer',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'contents', 'data-slot': 'root' },
  providers: [
    {
      provide: DRAWER_CONTEXT,
      useFactory: (c: DrawerComponent) => c.context,
      deps: [forwardRef(() => DrawerComponent)],
    },
  ],
})
export class DrawerComponent {
  readonly nOpen       = model<boolean>(false);
  readonly nId         = input<string>('');
  readonly nPersistent = input<boolean>(false);
  readonly nRole       = input<'dialog' | 'navigation'>('dialog');

  readonly nOpenChange = output<boolean>();

  private readonly _staticId  = `n-drawer-${++_drawerIdCounter}`;
  private readonly _triggerEl = signal<HTMLElement | null>(null);

  readonly drawerId      = computed(() => this.nId() || this._staticId);
  readonly titleId       = computed(() => `${this.drawerId()}-title`);
  readonly descriptionId = computed(() => `${this.drawerId()}-description`);

  readonly context: DrawerContext = {
    open:          this.nOpen,
    persistent:    this.nPersistent,
    role:          this.nRole,
    drawerId:      this.drawerId,
    titleId:       this.titleId,
    descriptionId: this.descriptionId,
    triggerEl:     this._triggerEl.asReadonly(),
    setTriggerEl:  (el) => this._triggerEl.set(el),
    setOpen:       (v) => this._setOpen(v),
    close:         () => this._setOpen(false),
  };

  private _setOpen(value: boolean): void {
    if (this.nOpen() === value) return;
    this.nOpen.set(value);
    this.nOpenChange.emit(value);
  }
}

import { Directive, ElementRef, OnDestroy, inject } from '@angular/core';
import { DRAWER_CONTEXT } from './drawer.context';

@Directive({
  selector: '[n-drawer-trigger]',
  standalone: true,
  host: {
    'data-slot': 'trigger',
    'aria-haspopup': 'dialog',
    '[attr.aria-expanded]': 'ctx.open()',
    '[attr.aria-controls]': 'ctx.open() ? ctx.drawerId() : null',
    '[attr.data-state]': 'ctx.open() ? "open" : "closed"',
    '(click)': 'ctx.setOpen(true)',
  },
})
export class DrawerTriggerDirective implements OnDestroy {
  protected readonly ctx = inject(DRAWER_CONTEXT);
  private readonly _host = inject<ElementRef<HTMLElement>>(ElementRef);

  constructor() {
    this.ctx.setTriggerEl(this._host.nativeElement);
  }

  ngOnDestroy(): void {
    this.ctx.setTriggerEl(null);
  }
}

import { A11yModule, FocusTrap, FocusTrapFactory } from '@angular/cdk/a11y';
import { Overlay, OverlayConfig, OverlayRef } from '@angular/cdk/overlay';
import { TemplatePortal } from '@angular/cdk/portal';
import { DOCUMENT } from '@angular/common';
import {
  AfterViewInit,
  ChangeDetectionStrategy,
  Component,
  ElementRef,
  OnDestroy,
  TemplateRef,
  ViewContainerRef,
  computed,
  effect,
  inject,
  input,
  signal,
  untracked,
  viewChild,
} from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { DRAWER_CONTEXT } from './drawer.context';
import { drawerContentVariants, type DrawerContentVariants } from './drawer.variants';

@Component({
  selector: 'n-drawer-content',
  standalone: true,
  imports: [A11yModule],
  template: `
    <ng-template #panel>
      @if (nBackdrop()) {
        <div
          class="fixed inset-0 bg-black/80 transition-opacity duration-300"
          [class.opacity-0]="!isVisible() || isClosing()"
          data-drawer-backdrop
          aria-hidden="true"
          (click)="handleBackdropClick()"
        ></div>
      }

      <div
        #panelEl
        [id]="ctx.drawerId()"
        [attr.role]="ctx.role()"
        aria-modal="true"
        [attr.aria-labelledby]="ctx.titleId()"
        [attr.aria-describedby]="ctx.descriptionId()"
        [attr.data-position]="nPosition()"
        [attr.data-shaking]="shaking() ? '' : null"
        data-slot="content"
        data-drawer
        tabindex="-1"
        [class]="classes()"
        (keydown)="handleKeydown($event)"
      >
        @if (nHandle() && (nPosition() === 'top' || nPosition() === 'bottom')) {
          <div class="flex justify-center pt-3 pb-1 shrink-0" aria-hidden="true">
            <div class="w-10 h-1.5 rounded-full bg-muted-foreground/30"></div>
          </div>
        }

        @if (!nHideClose()) {
          <button
            type="button"
            class="absolute right-4 top-4 rounded-sm opacity-70 ring-offset-background
                   transition-opacity hover:opacity-100 focus:outline-none focus:ring-2
                   focus:ring-ring focus:ring-offset-2 disabled:pointer-events-none"
            aria-label="Fechar"
            (click)="ctx.close()"
          >
            <svg
              xmlns="http://www.w3.org/2000/svg"
              width="16"
              height="16"
              viewBox="0 0 24 24"
              fill="none"
              stroke="currentColor"
              stroke-width="2"
              stroke-linecap="round"
              stroke-linejoin="round"
              aria-hidden="true"
            >
              <path d="M18 6 6 18"/><path d="m6 6 12 12"/>
            </svg>
          </button>
        }

        <ng-content />
      </div>
    </ng-template>
  `,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: { class: 'contents' },
})
export class DrawerContentComponent implements AfterViewInit, OnDestroy {
  readonly nPosition  = input<DrawerContentVariants['nPosition']>('right');
  readonly nSize      = input<'sm' | 'md' | 'lg' | 'xl' | 'full'>('md');
  readonly nScrollable = input<boolean>(false);
  readonly nHideClose  = input<boolean>(false);
  readonly nHandle     = input<boolean>(true);
  readonly nBackdrop   = input<boolean>(true);
  readonly nClass      = input<string>('');

  protected readonly ctx             = inject(DRAWER_CONTEXT);
  private readonly _overlay          = inject(Overlay);
  private readonly _vcr              = inject(ViewContainerRef);
  private readonly _focusTrapFactory = inject(FocusTrapFactory);
  private readonly _document         = inject(DOCUMENT);

  private readonly _panelTpl = viewChild.required<TemplateRef<unknown>>('panel');
  private readonly _panelEl = viewChild<ElementRef<HTMLElement>>('panelEl');

  private _overlayRef: OverlayRef | null = null;
  private _portal: TemplatePortal | null = null;
  private _focusTrap: FocusTrap | null = null;
  private _detachTimer?: ReturnType<typeof setTimeout>;

  protected readonly isVisible  = signal(false);
  protected readonly isClosing  = signal(false);
  protected readonly shaking    = signal(false);

  protected readonly classes = computed(() => {
    const pos = this.nPosition() ?? 'right';
    const size = this.nSize();
    const visible = this.isVisible() && !this.isClosing();

    const horizontal = pos === 'left' || pos === 'right';
    const sizeMap: Record<string, string> = horizontal
      ? { sm: 'w-64', md: 'w-80', lg: 'w-96', xl: 'w-[28rem]', full: 'w-full' }
      : { sm: 'h-48', md: 'h-72', lg: 'h-96', xl: 'h-[28rem]', full: 'h-full' };

    const offScreen: Record<string, string> = {
      left:   '-translate-x-full',
      right:  'translate-x-full',
      top:    '-translate-y-full',
      bottom: 'translate-y-full',
    };

    return mergeClasses(
      drawerContentVariants({ nPosition: pos }),
      sizeMap[size],
      'transition-transform duration-300',
      visible ? 'translate-x-0 translate-y-0 ease-out' : `${offScreen[pos]} ease-in`,
      this.nScrollable() && 'overflow-hidden',
      this.nClass(),
    );
  });

  constructor() {
    effect(() => {
      if (this.ctx.open()) {
        clearTimeout(this._detachTimer);
        this._attach();
      } else if (this._overlayRef) {
        this._beginDetach();
      }
    });
  }

  ngAfterViewInit(): void {
    this._portal = new TemplatePortal(this._panelTpl(), this._vcr);
  }

  ngOnDestroy(): void {
    clearTimeout(this._detachTimer);
    this._forceDetach();
  }

  private _attach(): void {
    if (!this._portal || this._overlayRef?.hasAttached()) return;

    const config = new OverlayConfig({
      positionStrategy: this._overlay.position().global(),
      scrollStrategy: this._overlay.scrollStrategies.block(),
      hasBackdrop: false,
      width: '100%',
      height: '100%',
    });

    this._overlayRef = this._overlay.create(config);
    this._overlayRef.attach(this._portal);
    this._document.body.classList.add('overflow-hidden');

    queueMicrotask(() => {
      this.isVisible.set(true);
      const el = this._panelEl()?.nativeElement;
      if (!el) return;
      this._focusTrap = this._focusTrapFactory.create(el);
      this._focusTrap.focusInitialElementWhenReady();
    });
  }

  private _beginDetach(): void {
    clearTimeout(this._detachTimer);
    this.isClosing.set(true);
    this.isVisible.set(false);

    const triggerEl = untracked(() => this.ctx.triggerEl());
    if (triggerEl) triggerEl.focus({ preventScroll: true });

    this._focusTrap?.destroy();
    this._focusTrap = null;

    this._detachTimer = setTimeout(() => {
      this.isClosing.set(false);
      this._forceDetach();
    }, 310);
  }

  private _forceDetach(): void {
    this._document.body.classList.remove('overflow-hidden');
    this._overlayRef?.dispose();
    this._overlayRef = null;
  }

  protected handleBackdropClick(): void {
    if (this.ctx.persistent()) { this._shake(); return; }
    this.ctx.close();
  }

  protected handleKeydown(event: KeyboardEvent): void {
    if (event.key !== 'Escape') return;
    event.preventDefault();
    event.stopPropagation();
    if (this.ctx.persistent()) { this._shake(); return; }
    this.ctx.close();
  }

  private _shake(): void {
    this.shaking.set(true);
    setTimeout(() => this.shaking.set(false), 450);
  }
}

import { ChangeDetectionStrategy, Component, computed, input } from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';

@Component({
  selector: 'n-drawer-header',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    'data-slot': 'header',
    '[class]': 'classes()',
  },
})
export class DrawerHeaderComponent {
  readonly nClass = input<string>('');

  protected readonly classes = computed(() =>
    mergeClasses('flex flex-col gap-1.5 px-6 py-4 shrink-0', this.nClass()),
  );
}

import { ChangeDetectionStrategy, Component, computed, input } from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';

@Component({
  selector: 'n-drawer-footer',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    'data-slot': 'footer',
    '[class]': 'classes()',
  },
})
export class DrawerFooterComponent {
  readonly nClass = input<string>('');

  protected readonly classes = computed(() =>
    mergeClasses('flex flex-col-reverse sm:flex-row sm:justify-end sm:gap-2 px-6 py-4 shrink-0', this.nClass()),
  );
}

import { ChangeDetectionStrategy, Component, computed, inject, input } from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { DRAWER_CONTEXT } from './drawer.context';

@Component({
  selector: 'n-drawer-title',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    'data-slot': 'title',
    'role': 'heading',
    'aria-level': '2',
    '[id]': 'ctx.titleId()',
    '[class]': 'classes()',
  },
})
export class DrawerTitleComponent {
  protected readonly ctx = inject(DRAWER_CONTEXT);
  readonly nClass = input<string>('');

  protected readonly classes = computed(() =>
    mergeClasses('text-lg font-semibold leading-none tracking-tight', this.nClass()),
  );
}

import { ChangeDetectionStrategy, Component, computed, inject, input } from '@angular/core';
import { mergeClasses } from '../../utils/merge-classes';
import { DRAWER_CONTEXT } from './drawer.context';

@Component({
  selector: 'n-drawer-description',
  standalone: true,
  template: `<ng-content />`,
  changeDetection: ChangeDetectionStrategy.OnPush,
  host: {
    'data-slot': 'description',
    '[id]': 'ctx.descriptionId()',
    '[class]': 'classes()',
  },
})
export class DrawerDescriptionComponent {
  protected readonly ctx = inject(DRAWER_CONTEXT);
  readonly nClass = input<string>('');

  protected readonly classes = computed(() =>
    mergeClasses('text-sm text-muted-foreground', this.nClass()),
  );
}

import { Directive, inject } from '@angular/core';
import { DRAWER_CONTEXT } from './drawer.context';

@Directive({
  selector: '[n-drawer-close]',
  standalone: true,
  host: {
    'data-slot': 'close',
    '(click)': 'ctx.close()',
  },
})
export class DrawerCloseDirective {
  protected readonly ctx = inject(DRAWER_CONTEXT);
}

import { InjectionToken, Signal } from '@angular/core';

export interface DrawerContext {
  readonly open: Signal<boolean>;
  readonly persistent: Signal<boolean>;
  readonly role: Signal<'dialog' | 'navigation'>;
  readonly drawerId: Signal<string>;
  readonly titleId: Signal<string>;
  readonly descriptionId: Signal<string>;
  readonly triggerEl: Signal<HTMLElement | null>;
  setOpen(value: boolean): void;
  close(): void;
  setTriggerEl(el: HTMLElement | null): void;
}

export const DRAWER_CONTEXT = new InjectionToken<DrawerContext>('DRAWER_CONTEXT');

import { cva, type VariantProps } from 'class-variance-authority';

export const drawerContentVariants = cva(
  ['fixed z-50 bg-background shadow-xl', 'flex flex-col'],
  {
    variants: {
      nPosition: {
        left:   'top-0 left-0 h-full border-r',
        right:  'top-0 right-0 h-full border-l',
        top:    'top-0 left-0 w-full border-b',
        bottom: 'bottom-0 left-0 w-full border-t',
      },
    },
    defaultVariants: { nPosition: 'right' },
  },
);

export type DrawerContentVariants = VariantProps<typeof drawerContentVariants>;

export * from './drawer.component';
export * from './drawer-trigger.directive';
export * from './drawer-content.component';
export * from './drawer-header.component';
export * from './drawer-footer.component';
export * from './drawer-title.component';
export * from './drawer-description.component';
export * from './drawer-close.directive';
export * from './drawer.context';
export * from './drawer.variants';

